var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"전조 프로토콜 발동, 3시간 경과","JPN":"前兆プロトコル発動より3時間経過","ENG":"3 hours after the Omen Protocol Activation","TWN":"前兆協議啟動，經過3小時。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 직할 도시 <color=#ffd34c>샤레이드</color> 외곽 구역","JPN":"管理局直轄都市<color=#ffd34c>シャレード</color>外郭地域","ENG":"Administration Direct Control City, <color=#ffd34c>Charade</color> Outskirts","TWN":"管理局直轄城市<color=#ffd34c>查雷德</color>外郭區域"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"CSE 레벨 확인, 레벨 2.8에서 점진적으로 상승 중…….","JPN":"CSEレベル確認、レベル2.8から徐々に上昇中……","ENG":"Checking the CSE Level... Slowly rising from Level 2.8...","TWN":"確認CSE等級，從等級2.8持續逐漸上升中……"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L8_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"앞으로 수분 뒤면, 저희가 있는 이곳도 대균열의 영향권에 휩쓸리게 되겠군요.","JPN":"数分後だと、私たちの居るここも大亀裂の影響圏内に入ることになりますね。","ENG":"In a few minutes, even this area will be caught within the Grand Dimension Crevice's influence.","TWN":"再過幾分鐘，我們所在之處也會被捲入大峽谷的影響範圍了。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"좋아, 모두들 준비하지.","JPN":"よし。皆、準備しよう。","ENG":"All right. Everyone, prepare yourselves.","TWN":"好，大家做好準備。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L12_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"단장님, 정말로 이곳에 방어전선을 구축해도 괜찮은 걸까요?","JPN":"団長、本当にここに防衛前線を張ってもいいのでしょうか？","ENG":"Commander, are you sure it's wise to establish a defense line here?","TWN":"團長，真的要在這裡構築防禦戰線嗎？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L13_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"이곳은 민간 거주 구역과 그리 멀지 않은 곳입니다.","JPN":"ここは民間居住区域に近い場所ですが……","ENG":"This location isn't far from a civilian residential district.","TWN":"這裡離住民區不遠。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"혹시라도 아직까지 대피하지 못한 민간인들이 전투에 휘말릴 가능성이 있습니다.","JPN":"もしまだ避難できていない住民がいたら、戦闘に巻き込まれる可能性があります。","ENG":"There's a chance civilians who haven't evacuated yet could be caught up in the fighting.","TWN":"萬一還有尚未完成撤離的平民，也有被捲入戰鬥的可能性。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L19_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_C","text":{"KOREA":"기사단에서 피난용 함선을 준비해 두었습니다!","JPN":"騎士団が避難用の艦船を用意しました！","ENG":"The Order has prepared evacuation ships!","TWN":"騎士團已經準備好用於避難的艦船了！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"},"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L20_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_C","text":{"KOREA":"시민권과 관계없이, 몸이 불편한 분과 노약자를 우선으로 탑승을 진행하겠습니다!","JPN":"市民権の有無を問わず、体の不自由な方やご高齢の方から優先してご搭乗いただきます！","ENG":"Regardless of citizenship status, we will begin boarding by prioritizing the infirm and the elderly!","TWN":"優先讓行動不便者與老弱者登船，不論是否擁有市民身分！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_C","text":{"KOREA":"모두 안심하고, 저희의 통제에 따라 주시기 바랍니다!","JPN":"皆さん、安心して私たちの指示に従ってください！","ENG":"Everyone, please remain calm and follow our instructions!","TWN":"請大家放心，並依照我們的指揮行動！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"누님, 이쪽 구역의 민간인은 전부 대피를 완료하였습니다.","JPN":"メデイアさん、こっちの区域の民間人は全員避難させました。","ENG":"M-Medea, all civilians in this sector have completed evacuation.","TWN":"姐姐，這一區的平民已經全部完成撤離了。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L24_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"문제는 함선의 수용 인원인데…….","JPN":"問題は、艦船の収容人数ですが……","ENG":"The problem is the ships' passenger capacity...","TWN":"問題在於艦船的收容人數……"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"쳇, 가문 격납고에 박혀 있던 고물까지 죄다 끌어모았는데, 이걸로도 부족하다고?","JPN":"ちっ、家の格納庫に放置されてたボロ艦まで全部出してきたのに、これでも足りないというの？","ENG":"Tch. I hauled in every last junk heap rotting in the family hangar, and it's still not enough?","TWN":"嘖，我把家族機庫裡的老古董全都拖出來了，結果還是不夠嗎？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L28_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"최대 정원을 초과해도 좋아! 그러니까……","JPN":"定員を越えても構わないわ！　だから……","ENG":"I don't care if we exceed maximum capacity. Just–","TWN":"就算超過乘載人數上限也沒關係！所以……"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L29_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"음!?","JPN":"えっ？","ENG":"Huh?!","TWN":"嗯！？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}},"sfx":"FX_COMBAT_MECHANIC_COFFIN_START"},{"id":"L31_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"안뇽~ 조디악 나이츠의…… <color=#ffd34c>양대가리</color> 씨 맞지?","JPN":"やっほ～ゾディアックナイツの……<color=#ffd34c>羊頭</color>さん、だよね？","ENG":"Hey there! You're the Zodiac Knights'... <color=#ffd34c>Sheep Head</color>, right?","TWN":"哈囉～你是十二宮騎士團的……<color=#ffd34c>羊頭</color>吧？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L34_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"양대가리……?","JPN":"羊頭……？","ENG":"Sheep Head...?","TWN":"羊頭……？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L37_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"메데이아 언니! 레온하르트… 줄리아 언니가 저희를 도와주셨어요!","JPN":"メデイアさん！　レオンハルト……ジュリアさんが力を貸してくださったんです！","ENG":"Medeia! Leonhardt– I mean, Julia helped us!","TWN":"美狄亞姐姐！里恩哈特……茱莉亞姐姐來幫我們了！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L38_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"함선이, 함선이 잔뜩 있어요!","JPN":"艦船が、艦船がいっぱいあります！","ENG":"There are ships, tons of ships!","TWN":"艦船，有好多艦船！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"오지만디아스 씨의 스폰서들이 후원해 준 함선이야.","JPN":"オジマンディアスさんのスポンサーが送ってくれた艦船だよ。","ENG":"They're ships sponsored by Ozymandias's sponsors.","TWN":"這些是奧茲曼迪亞斯的贊助商們支援的艦船。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"회사 로고 잘 보이게 피난 방송 좀 찍어달라고 하더라?","JPN":"企業のロゴがよく映るように避難の様子を撮影してほしいんだってさ～","ENG":"They asked us to film an evacuation broadcast with the company logos clearly visible, you know?","TWN":"他們說想拍一段避難廣播，希望能把公司商標拍清楚一點？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"원래 회사라는 게, 가식 좀 떨어도 착한 이미지를 만들어 두면 손해 볼 게 없거든.","JPN":"まあ、企業ってそういうもんなんだよね。多少は偽善って捉えられても、いい印象作っといた方が後のためって感じ？","ENG":"That's how companies are. Even if it's all for show, building a “positive” image never hurts.","TWN":"公司這種東西啊，就算有點虛偽，只要塑造一下善良的形象就不會吃虧。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"……훗.","JPN":"……ふっ。","ENG":"...Heh.","TWN":"……哼。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"하여간 재수없는 년, 보낼 거면 일찍 보내든가.","JPN":"まったく、ムカつく女ね。送るならもっと早くしなさいっての。","ENG":"Seriously, that damn woman. If she was going to send them, she could've done it sooner.","TWN":"總之真是個倒胃口的女人，要送的話就早點送啊。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"……물론, 데이비스 경께서 가문의 재력을 이용하여 후방을 지원하고 계시지만.","JPN":"……もちろん、デイヴィス卿が家門の財力を使って後方支援してくださっていますが。","ENG":"...Of course, Dame Davis is supporting the rear with the family's wealth, but...","TWN":"……當然，戴維斯卿也正動用家族財力在後方支援。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"애초에 이 거점은 전술적으로 잃을 것이 너무 많습니다.","JPN":"そもそも、この拠点は戦術的に失うものが多すぎます。","ENG":"From a tactical standpoint, this strongpoint has far too much to lose.","TWN":"當初這個據點在戰略上就失去太多了。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"부단장의 우려는 충분히 이해해.","JPN":"副団長が懸念していることは十分わかっている。","ENG":"I understand your concern, Deputy.","TWN":"我完全理解副團長的擔憂。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"하지만 이 거점을 잃으면, 선로전환기를 배치할 지점의 루트 확보가 어려워져.","JPN":"だがこの拠点を失えば、線路転換器を配置する地点へのルート確保が難しくなるんだ。","ENG":"But if we lose this position, securing a route to the Track Switcher deployment site will become difficult.","TWN":"但是一旦失去這個據點，就難以確保配置線路轉換器的路徑。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"모든 이들이 각자의 위치에서 각자의 역할을 다하고 있다.","JPN":"皆それぞれの持場で、それぞれの役割を果たしている。","ENG":"Everyone is fulfilling their role, each in their own place.","TWN":"所有人都在各自的位置履行各自的職責。"},"stage":{"bg":"PROLOGUE_01","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"그리고 우리들은 기사. 검과 창으로 스스로의 정의를 관철하는 자.","JPN":"そして我々は騎士。剣と槍で自らの正義を貫く者だ。","ENG":"And we are knights. Those who uphold our justice with blade and spear.","TWN":"而我們是騎士，是以劍與槍貫徹自身正義之人。"},"stage":{"bg":"PROLOGUE_01","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"그러니 우리는 작전이 끝나는 그 마지막 순간까지, 이 거점을 반드시 지켜낸다.","JPN":"ゆえに我々は、作戦が終わる最後の瞬間まで、この拠点を死守する。","ENG":"So we will hold this position to the very last moment, until the operation is complete.","TWN":"所以，直到作戰結束的最後一刻，我們都必須死守這個據點。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"이걸로 대답이 되었나, 부단장?","JPN":"これで答えになったかな？　副団長。","ENG":"Does that answer your question, Deputy?","TWN":"這樣的回答可以嗎，副團長？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"……물론입니다, 단장님.","JPN":"……もちろんです、団長。","ENG":"...Yes, Captain.","TWN":"……當然囉，團長。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"단장님, 척후 결과 보고야!","JPN":"団長、偵察の報告だよ！","ENG":"Captain, scout report!","TWN":"團長，報告偵查結果！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L17_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"거점으로부터 거리 500…! 갑자기 그림자가 나타났어……!","JPN":"拠点から距離500……！　急にシャドウが現れた……！","ENG":"500 distance from the strongpoint...! A Shadow appeared out of nowhere...!","TWN":"距離據點500……！突然出現暗影……！"},"stage":{"bg":"MAINSTREAM_124010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"추정 등급 5종! 관리국에서 보고 받았던 그림자의 특징과 일치해!","JPN":"推定ランクは第5種！　管理局から報告を受けたシャドウの特徴と一致！","ENG":"Estimated to be a Category 5 threat! It matches the Shadow's characteristics from the Administration's report!","TWN":"判定等級為第5類！與管理局回報過的暗影特徵一致！"},"stage":{"bg":"MAINSTREAM_124010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"좋다! 조디악 나이츠 전원, 대열을 갖추도록!","JPN":"よし！　ゾディアックナイツ、全員隊列を整えろ！","ENG":"Good. All Zodiac Knights, form up!","TWN":"很好！十二宮騎士團全員，整隊！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L22_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"지금부터 그림자 토벌을 시작한다!","JPN":"これよりシャドウ討伐を開始する！","ENG":"From this moment, we will commence the Shadow subjugation!","TWN":"現在開始討伐暗影！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_CROWD_NOISE_04"}]`);export{e as default};